import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class InputHandlerServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        response.setContentType("text/html");

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h2>User Input:</h2>");

        // Sanitize and encode user input to prevent XSS
        String sanitizedInput = sanitizeUserInput(userInput);

        out.println("<p>" + sanitizedInput + "</p>"); // Safely display sanitized user input
        out.println("</body>");
        out.println("</html>");

    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input sanitization and encoding here
        // Example: Using OWASP Java Encoder to encode user input
